/**
 * Module dependencies.
 */

const express = require('./lib/express');
const bodyParser = require('body-parser');

/**
 * Expose the express constructor.
 */

exports = module.exports = express;

/**
 * Expose middleware.
 */

exports.json = bodyParser.json;
exports.raw = bodyParser.raw;
exports.text = bodyParser.text;
exports.urlencoded = bodyParser.urlencoded;

/**
 * Expose the mime lookup function.
 */

exports.mime = require('send').mime;

/**
 * Expose Router constructor.
 */

exports.Router = require('./lib/router');

/**
 * Expose Route constructor.
 */

exports.Route = require('./lib/router/route');

/**
 * Expose middleware
 */

exports.query = require('./lib/middleware/query');
exports.static = require('serve-static');

/**
 * Replace removed middleware with an appropriate error message.
 */

["bodyParser", "compress", "cookieSession", "session", "logger", "cookieParser",
  "favicon", "responseTime", "errorHandler", "timeout", "methodOverride", "vhost",
  "csrf", "directory", "limit", "multipart", "staticCache"].forEach(function (name) {
  Object.defineProperty(exports, name, {
    get: function () {
      throw new Error('Most middleware is no longer bundled with Express and must be installed separately. Please see https://github.com/senchalabs/connect#middleware.');
    },
    configurable: true
  });
});